// 1. Webhook(텔레그램)에서 URL을 가져옵니다.
const youtubeUrl = items[0].json.message.text.trim();

// URL을 안전한 파이썬 문자열로 만듭니다.
const safeUrlJson = JSON.stringify(youtubeUrl);

// 2. 실행할 Python 스크립트 문자열을 만듭니다.
const pythonScript = `
import subprocess, json, os, glob, sys; from subprocess import DEVNULL

try:
    subprocess.run(["pip", "install", "yt-dlp"], stdout=DEVNULL, stderr=DEVNULL)
except:
    pass

base_filename = "temp_transcript"

for f in glob.glob(base_filename + "*"):
    try:
        os.remove(f)
    except:
        pass

# JavaScript에서 만든 안전한 URL 변수를 주입합니다.
url_from_js = ${safeUrlJson}

cmd = [
    "yt-dlp",
    "--write-subs",
    "--write-auto-subs",
    "--skip-download",
    "--sub-format", "json3",
    "--sub-langs", "ko",
    "--output", base_filename,
    "--no-warnings",
    "--force-overwrites",
    url_from_js
]

transcript_data = {"error": "Unknown Python error"}

try:
    subprocess.run(cmd, stdout=DEVNULL, stderr=DEVNULL)

    created_files = glob.glob(base_filename + "*.ko*.json3") 

    if created_files:
        actual_filename = created_files[0]
        try:
            with open(actual_filename, "r", encoding="utf-8") as f:
                transcript_data = json.load(f) # 성공!

        except Exception as e:
            transcript_data = {"error": "File read error: " + str(e)}
        finally:
            try:
                os.remove(actual_filename)
            except:
                pass

    else:
        transcript_data = {"error": "yt-dlp did not create a 'ko' subtitle file. Check URL or if 'ko' subtitles exist."}

    for f in glob.glob(base_filename + "*.json3"):
        try:
            if 'actual_filename' not in locals() or f != actual_filename:
                os.remove(f)
        except:
            pass

except Exception as e:
    transcript_data = {"error": "A Python error occurred: " + str(e)}

print(json.dumps(transcript_data))
`;

// 3. 스크립트가 n8n에서 깨지는 것을 막기 위해 Base64로 인코딩합니다.
const base64Script = Buffer.from(pythonScript).toString('base64');

// --- !! 🚨 여기가 윈도우 전용 최종 수정 사항입니다 !! ---
// 4. 윈도우의 PowerShell을 사용하여 Base64를 디코딩하고
//    그 결과를 파이썬으로 바로 전달하여 실행합니다.
//    (python3 - 는 '표준 입력'으로 스크립트를 받으라는 의미입니다)
const finalCommand = `powershell -Command "[System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String('${base64Script}')) | python3 -"`;

// 5. 이 최종 명령어를 n8n의 올바른 출력 형식으로 반환합니다.
return [
  {
    json: {
      commandToRun: finalCommand
    }
  }
];

// 'Code in JavaScript2' (세 번째 노드)에 이 코드를 전부 붙여넣으세요.

// 1. Execute Command의 'json' 객체에서 'stdout'을 가져옵니다.
const rawOutput = $('Execute Command').item.json.stdout;
let data;
let jsonString = null;

// 2. output이 실제로 존재하고(null/undefined가 아님) 문자열인지 확인합니다.
if (!rawOutput || typeof rawOutput !== 'string') {
    const stderr = $('Execute Command').item.json.stderr || "No stderr";
    return [{
        json: {
            error: "stdout was undefined or not a string. Cannot parse.",
            stderr_received: stderr
        }
    }];
}

// 3. (핵심 수정) ANSI 이스케이프 코드(색상 코드)와 \r (캐리지 리턴) 문자를 모두 제거합니다.
const ansiRegex = /[\u001b\u009b][[()#;?]*.{0,2}(?:[0-9]{1,4}(?:;[0-9]{0,4})*)?[0-9A-ORZcf-nqry=><]/g;
const output = rawOutput.replace(ansiRegex, '').replace(/\r/g, '');

// 4. (핵심 수정) 전체 출력을 줄(line) 단위로 나눕니다.
try {
  const lines = output.split('\n');

  // 5. 맨 마지막 줄부터 거꾸로 탐색하여, '{'로 시작하는 첫 번째 줄을 찾습니다.
  //    이것이 우리가 찾는 JSON입니다.
  for (let i = lines.length - 1; i >= 0; i--) {
    const line = lines[i].trim(); // 혹시 모를 앞뒤 공백 제거
    if (line.startsWith('{')) {
      jsonString = line;
      break; // JSON을 찾았으므로 중단
    }
  }

  if (jsonString === null) {
      // 깨끗해진 stdout에서 JSON을 찾지 못했습니다.
      throw new Error("No line starting with '{' was found in cleaned stdout.");
  }

  // 6. 찾은 JSON 문자열을 파싱(변환)합니다.
  data = JSON.parse(jsonString);

} catch (e) {
  // JSON 파싱에 실패하면, 에러 객체를 반환합니다.
  return [{
    json: {
      error: "Failed to parse JSON from stdout",
      details: e.message,
      stdout_received: rawOutput // 디버깅을 위해 *원본* stdout을 포함
    }
  }];
}

// 7. JSON 파싱에 성공했는지 확인합니다.
// (만약 자막이 없는 영상이라 {"error":...}가 왔어도, data.error로 잡힙니다)
if (data.error) {
  // Python 스크립트가 에러를 반환했습니다.
  return [{ json: data }];
}

// 8. 진짜 성공 ({"wireMagic":...})한 경우, 자막을 정제합니다.
try {
  const segments = data.events
    .filter(event => event.segs)
    .flatMap(event => event.segs)
    .map(seg => seg.utf8);

  // \n (줄바꿈)을 공백으로 바꾸고, 모든 텍스트를 하나로 합칩니다.
  const fullTranscript = segments.join(' ').replace(/\\n/g, ' ').replace(/\n/g, ' ');

  // 9. 최종 결과 반환
  return [{
    json: {
      transcript: fullTranscript
    }
  }];

} catch (e) {
  // 자막 정제(parsing) 중 오류 발생
  return [{
    json: {
      error: "Failed to parse the structure of the subtitle JSON.",
      details: e.message,
      json_received: data
    }
  }];
}

// 1. 검색 결과를 안전하게 가져옵니다.
// searchInformation 변수를 사용하지 않고, organic_results를 직접 가져옵니다.
// ❗ 이 코드가 정상 작동하려면 Google search 노드의 출력이 JSON 형식이어야 합니다.
const allOrganicResults = $input.first().json.organic_results; 
let searchResults = [];

try {
    // 검색 결과(organic_results)를 가져와 상위 5개만 가공합니다.
    // 'allOrganicResults'가 유효한 배열인지 확인합니다.
    if (Array.isArray(allOrganicResults)) {
        searchResults = allOrganicResults
            .slice(0, 5)
            .map(r => ({
                title: r.title,
                snippet: r.snippet,
                source: r.source_title || r.source || r.link
            }));
    }
} catch (e) {
    // 오류 발생 시, 빈 배열을 유지합니다.
    console.error("검색 결과를 가져오거나 처리하는 중 오류가 발생했습니다.", e);
}

// 4. (🌟 수정 없음) 원본 텍스트가 저장된 'Code in JavaScript2' 노드의 'transcript' 키를 참조합니다.
const originalText = $('Code in JavaScript2').first().json.transcript;

// 5. 프롬프트를 정의하고, 변수를 삽입합니다.
// (요청하신 프롬프트는 수정 없이 유지합니다.)
const prompt = `너는 요약 봇이야.
아래 [원본 기사]와 [검색 결과]를 비교해서,
[원본 기사]가 검색 결과와 비슷한지 분석하고,

가짜뉴스인지 아닌지 판단해줘
판단 기준은 비슷한 키워드의 영상의 갯수가 얼마나 되는지(5개 이상)
다른 설명을 모두 생략하고 아래 [JSON 형식]에 맞춰서 한 줄로 가짜뉴스인지 아닌지와 
비슷한 영상이 몇 개 있었는지 같이 분석해줘.

[원본 기사]
${originalText}

[검색 결과]
${JSON.stringify(searchResults, null, 2)}
`;

// 6. 다음 노드로 보낼 데이터를 반환(return)합니다.
return [
    {
        json: {
            generatedPrompt: prompt
        }
    }
];
